// Функция для обработки текста и поиска ссылок
const renderTextWithLinks = (text) => {
  const urlRegex = /(https?:\/\/[^\s]+)/g;
  return text.split(urlRegex).map((part, index) => {
    if (part.match(urlRegex)) {
      return (
        <a key={index} href={part} target="_blank" rel="noopener noreferrer" style={{ color: "#2563EB", textDecoration: "underline", wordBreak: "break-all" }}>
          {part}
        </a>
      );
    }
    return part;
  });
};

function ChevronDown({ open }) {
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none" style={{ transition: "transform 0.3s ease", transform: open ? "rotate(180deg)" : "rotate(0deg)", flexShrink: 0 }}>
      <path d="M5 7.5L10 12.5L15 7.5" stroke="#112250" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

function AccordionItem({ question, answer, delay = 0 }) {
  const [open, setOpen] = useState(false);
  const [visible, setVisible] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(([entry]) => { if (entry.isIntersecting) setVisible(true); }, { threshold: 0.1 });
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, []);

  return (
    <div ref={ref} style={{ border: "1px solid #E5E7EB", borderRadius: "14px", overflow: "hidden", backgroundColor: "white", opacity: visible ? 1 : 0, transform: visible ? "translateY(0)" : "translateY(16px)", transition: `opacity 0.4s ease ${delay}ms, transform 0.4s ease ${delay}ms` }}>
      <button onClick={() => setOpen(!open)} style={{ width: "100%", display: "flex", alignItems: "center", justifyContent: "space-between", padding: "18px 22px", textAlign: "left", background: "none", border: "none", cursor: "pointer" }}>
        <span style={{ color: "#111827", fontWeight: 600, fontSize: "15px", paddingRight: "16px" }}>{question}</span>
        <ChevronDown open={open} />
      </button>
      <div style={{ maxHeight: open ? "800px" : "0", overflow: "hidden", transition: "max-height 0.35s ease" }}>
        <div style={{ padding: "0 22px 18px", color: "#6B7280", fontSize: "14px", lineHeight: 1.7, borderTop: "1px solid #E5E7EB", paddingTop: "14px" }}>
          {renderTextWithLinks(answer)}
        </div>
      </div>
    </div>
  );
}

function useReveal(delay = 0) {
  const [visible, setVisible] = useState(false);
  useEffect(() => { const timer = setTimeout(() => setVisible(true), delay); return () => clearTimeout(timer); }, [delay]);
  return { ref: null, style: { opacity: visible ? 1 : 0, transform: visible ? "translateY(0)" : "translateY(24px)", transition: "opacity 0.6s ease, transform 0.6s ease" } };
}

export default function FaqPage() {
  const [activeCategory, setActiveCategory] = useState("Банковский сектор");
  const [search, setSearch] = useState("");
  const [questionText, setQuestionText] = useState("");
  const [sent, setSent] = useState(false);

  const title1 = useReveal(100);
  const title2 = useReveal(250);
  const subtitle = useReveal(400);
  const searchReveal = useReveal(550);
  const cardReveal = useReveal(300);

  const filtered = FAQ_DATA.filter((section) => section.category === activeCategory).map((section) => ({
    ...section,
    items: section.items.filter((item) => item.question.toLowerCase().includes(search.toLowerCase()) || item.answer.toLowerCase().includes(search.toLowerCase())),
  })).filter((section) => section.items.length > 0);

  return (
    <div style={{ minHeight: "100vh", background: "#ffffff" }}>
      <section style={{ backgroundColor: "#112250", padding: "90px 32px", position: "relative", overflow: "hidden" }}>
        <div style={{ position: "relative", maxWidth: "1240px", margin: "0 auto", display: "grid", gridTemplateColumns: "1fr 1fr", gap: "48px", alignItems: "flex-start" }}>
          <div>
            <div style={title1.style}><h1 style={{ fontSize: "56px", fontWeight: 900, color: "white", margin: 0 }}>Часто задаваемые</h1></div>
            <div style={title2.style}><h1 style={{ fontSize: "56px", fontWeight: 900, color: "white", margin: "0 0 18px" }}>вопросы</h1></div>
            <div style={subtitle.style}><p style={{ color: "rgba(255,255,255,0.7)", fontSize: "16px", lineHeight: 1.7, marginBottom: "28px" }}>Найдите быстрые ответы на свои вопросы о финансовых инструментах и безопасности.</p></div>
            <div style={searchReveal.style}>
              <div style={{ position: "relative" }}>
                <input type="text" value={search} onChange={(e) => setSearch(e.target.value)} placeholder="Опишите вашу проблему или задайте вопрос..." style={{ width: "100%", backgroundColor: "rgba(255,255,255,0.12)", border: "1px solid rgba(255,255,255,0.2)", borderRadius: "14px", padding: "15px 48px 15px 18px", color: "white", outline: "none" }} />
                <div style={{ position: "absolute", right: "16px", top: "50%", transform: "translateY(-50%)", color: "rgba(255,255,255,0.6)" }}><MdiIcon path={mdiMagnify} size={25} /></div>
              </div>
            </div>
          </div>
          <div style={{ ...cardReveal.style, backgroundColor: "rgba(255,255,255,0.88)", borderRadius: "22px", padding: "28px", boxShadow: "0 18px 42px rgba(0,0,0,0.24)" }}>
            <h3 style={{ color: "#111827", fontWeight: 800, fontSize: "20px", margin: "0 0 16px" }}>Задать вопрос</h3>
            <textarea value={questionText} onChange={(e) => setQuestionText(e.target.value)} placeholder="Опишите вашу ситуацию..." rows={5} style={{ width: "100%", border: "1px solid #E5E7EB", borderRadius: "14px", padding: "14px 16px", marginBottom: "16px", outline: "none", resize: "none" }} />
            <button onClick={() => { if(questionText.trim()){setSent(true); setTimeout(() => setSent(false), 3000); setQuestionText("");}}} style={{ width: "100%", backgroundColor: "#112250", color: "white", border: "none", cursor: "pointer", fontWeight: 700, padding: "14px", borderRadius: "14px" }}>{sent ? "✓ Отправлено!" : "Отправить"}</button>
          </div>
        </div>
      </section>
      <section style={{ backgroundColor: "white", padding: "48px 32px 90px" }}>
        <div style={{ maxWidth: "1240px", margin: "0 auto" }}>
          <div style={{ display: "flex", flexWrap: "wrap", gap: "10px", marginBottom: "36px" }}>
            {CATEGORIES.map((cat, index) => (
              <button key={cat.label} onClick={() => { setActiveCategory(cat.label); setSearch(""); }} style={{ display: "flex", alignItems: "center", gap: "7px", padding: "10px 18px", borderRadius: "999px", fontSize: "14px", fontWeight: 600, cursor: "pointer", border: activeCategory === cat.label ? "1px solid #112250" : "1px solid #E5E7EB", backgroundColor: activeCategory === cat.label ? "#112250" : "white", color: activeCategory === cat.label ? "white" : "#374151" }}>
                <span style={{ width: "8px", height: "8px", borderRadius: "50%", backgroundColor: activeCategory === cat.label ? "white" : cat.dot }} />
                {cat.label}
              </button>
            ))}
          </div>
          {filtered.length > 0 ? (
            filtered.map((section, sIdx) => (
              <div key={sIdx} style={{ marginBottom: "34px" }}>
                <h2 style={{ color: "#112250", fontWeight: 800, fontSize: "22px", marginBottom: "16px" }}>{section.title}</h2>
                <div style={{ display: "flex", flexDirection: "column", gap: "10px" }}>
                  {section.items.map((item, i) => <AccordionItem key={i} {...item} delay={i * 80} />)}
                </div>
              </div>
            ))
          ) : (
            <div style={{ textAlign: "center", padding: "80px 0" }}><p style={{ color: "#111827", fontWeight: 600 }}>В данном разделе пока нет вопросов.</p></div>
          )}
        </div>
      </section>
    </div>
  );
}